artifacts.preview:
{
  "name": "healthgrades",
  "displayName": "Healthgrades",
  "version": "1.0.0",
  "description": "Find doctors with Healthgrades - search providers, read reviews, and check credentials",
  "author": "Canifi LifeOS",
  "category": "Healthcare & Telehealth",
  "authentication": {
    "type": "browser",
    "loginUrl": "https://www.healthgrades.com/login",
    "loggedInIndicator": "[data-testid='user-menu']"
  },
  "capabilities": [
    "search-doctors",
    "read-reviews",
    "check-credentials",
    "hospital-ratings",
    "compare-providers",
    "find-specialists"
  ],
  "requiredEnvVars": [
    "HEALTHGRADES_EMAIL",
    "HEALTHGRADES_PASSWORD"
  ],
  "endpoints": {
    "base": "https://www.healthgrades.com",
    "find": "https://www.healthgrades.com/find-a-doctor"
  },
  "rateLimit": {
    "requests": 60,
    "period": "minute"
  }
}
